import json
import os
import re

# Load package data from file
packages_path = 'temp/query_db_22.json'
api_packages = []

# Parse VersionInfo from string format
def parse_version_info(version_info_str):
    try:
        # Extract IsRelease and Ordinal from the string format
        # Format looks like: {\n  "IsRelease": true,\n  "Ordinal": 29\n}
        if 'IsRelease\": true' in str(version_info_str) or '"IsRelease": true' in str(version_info_str):
            is_release = True
        else:
            is_release = False

        # Extract ordinal
        ordinal_match = re.search(r'"Ordinal":\s*(\d+)', str(version_info_str))
        if ordinal_match:
            ordinal = int(ordinal_match.group(1))
        else:
            ordinal = 0

        return {
            'is_release': is_release,
            'ordinal': ordinal
        }
    except:
        return {'is_release': False, 'ordinal': 0}

# Load packages (we need to read the correct file)
# Let's check what files exist in the temp directory
files = os.listdir('temp') if os.path.exists('temp') else []
print('Files in temp:', files)

# Try to load the packages data
packages_key = 'var_functions.query_db:22'
# This might be a file path string
if isinstance(packages_key, str) and os.path.isfile(packages_key):
    with open(packages_key, 'r') as f:
        all_packages_raw = json.load(f)
else:
    # It might be stored in locals
    all_packages_raw = var_functions.query_db:22

print('Raw packages type:', type(all_packages_raw))
print('Number of packages:', len(all_packages_raw))

# Process package data
packages_dict = {}
for pkg in all_packages_raw[:2000]:  # Process first 2000 for testing
    if isinstance(pkg, dict) and 'Name' in pkg and 'Version' in pkg:
        name = pkg['Name']
        version = pkg['Version']
        version_info = parse_version_info(pkg.get('VersionInfo', ''))

        if version_info['is_release']:
            # Keep track of the latest release version (max ordinal)
            if name not in packages_dict or version_info['ordinal'] > packages_dict[name]['ordinal']:
                packages_dict[name] = {
                    'version': version,
                    'ordinal': version_info['ordinal']
                }

print(f'Unique packages with releases: {len(packages_dict)}')
print('Sample packages:', list(packages_dict.items())[:5])

print('__RESULT__:')
print(json.dumps({'message': 'Package processing complete', 'count': len(packages_dict)}))

