import json, re

packages = var_functions.query_db:32
pv_mappings = var_functions.query_db:38
proj_info = var_functions.query_db:20

# Step 1: Get latest releases
latest = {}
for p in packages:
    m = re.search(r'Ordinal":\s*(\d+)', p['VersionInfo'])
    ordinal = int(m.group(1)) if m else 0
    if 'IsRelease": true' in p['VersionInfo']:
        if p['Name'] not in latest or ordinal > latest[p['Name']]['ordinal']:
            latest[p['Name']] = {'version': p['Version'], 'ordinal': ordinal}

# Step 2: Map packages to repos
pv_to_repo = {}
for pv in pv_mappings:
    if pv['System'] == 'NPM':
        key = (pv['Name'], pv['Version'])
        pv_to_repo[key] = pv['ProjectName']

# Step 3: Extract stars
repo_stars = {}
for info in proj_info:
    txt = info['Project_Information']
    if txt == 'None' or not txt:
        continue
    m = re.search(r'(\d+[\d,]*)\s+stars?', txt)
    if m:
        stars = int(m.group(1).replace(',',''))
        m2 = re.search(r'project\s+(\S+?)\s', txt)
        if m2:
            repo_stars[m2.group(1)] = stars

# Step 4: Match packages with stars
results = []
for name, info in latest.items():
    key = (name, info['version'])
    if key in pv_to_repo:
        repo = pv_to_repo[key]
        if repo in repo_stars:
            results.append({'package': name, 'version': info['version'], 'stars': repo_stars[repo], 'repo': repo})

# Step 5: Top 5
top5 = sorted(results, key=lambda x: x['stars'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps(top5))

