import json, re, os

# Load data
packages = json.load(open(locals()['var_functions.query_db:58'], 'r')) if isinstance(locals()['var_functions.query_db:58'], str) and os.path.isfile(locals()['var_functions.query_db:58']) else locals()['var_functions.query_db:58']
pv_mappings = json.load(open(locals()['var_functions.query_db:38'], 'r')) if isinstance(locals()['var_functions.query_db:38'], str) and os.path.isfile(locals()['var_functions.query_db:38']) else locals()['var_functions.query_db:38']
proj_info = json.load(open(locals()['var_functions.query_db:20'], 'r')) if isinstance(locals()['var_functions.query_db:20'], str) and os.path.isfile(locals()['var_functions.query_db:20']) else locals()['var_functions.query_db:20']

# Step 1: Find latest release for each package
latest = {}
for p in packages:
    name = p['Name']
    vi = p['VersionInfo']
    m = re.search(r'Ordinal":\s*(\d+)', vi)
    ordinal = int(m.group(1)) if m else 0
    if 'IsRelease": true' in vi:
        if name not in latest or ordinal > latest[name]['ordinal']:
            latest[name] = {'version': p['Version'], 'ordinal': ordinal}

# Step 2: Map package versions to repos
pv_to_repo = {}
for pv in pv_mappings:
    if pv['System'] == 'NPM':
        pv_to_repo[(pv['Name'], pv['Version'])] = pv['ProjectName']

# Step 3: Extract stars from project info
repo_stars = {}
for info in proj_info:
    txt = info.get('Project_Information', '')
    if txt and txt != 'None':
        m = re.search(r'(\d+[\d,]*)\s+stars?', txt)
        if m:
            stars = int(m.group(1).replace(',', ''))
            m2 = re.search(r'project\s+(\S+?)\s', txt)
            if m2:
                repo_stars[m2.group(1)] = stars

# Step 4: Find packages with stars
matches = []
for name, data in latest.items():
    key = (name, data['version'])
    if key in pv_to_repo:
        repo = pv_to_repo[key]
        if repo in repo_stars:
            matches.append({
                'package': name,
                'version': data['version'],
                'stars': repo_stars[repo],
                'repo': repo
            })

# Step 5: Get top 5
top5 = sorted(matches, key=lambda x: x['stars'], reverse=True)[:5]

print('__RESULT__:')
print(json.dumps(top5))

